import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Define custom CUDA kernel for fully fused cosine similarity loss with vectorized memory access
cosine_loss_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <math.h>
#include <cassert>

template<int THREADS_PER_BLOCK, int ELEMENTS_PER_THREAD>
__global__ void cosine_loss_fused_kernel(
    const float* __restrict__ predictions,
    const float* __restrict__ targets,
    float* __restrict__ output,
    int batch_size,
    int feature_size
) {
    // Static assertion for compile-time safety
    static_assert(THREADS_PER_BLOCK >= 32, "THREADS_PER_BLOCK must be at least 32");
    static_assert((THREADS_PER_BLOCK & (THREADS_PER_BLOCK - 1)) == 0, "THREADS_PER_BLOCK must be a power of two");
    static_assert(ELEMENTS_PER_THREAD > 0, "ELEMENTS_PER_THREAD must be positive");

    __shared__ float shared_dot[THREADS_PER_BLOCK];
    __shared__ float shared_pred_norm[THREADS_PER_BLOCK];
    __shared__ float shared_target_norm[THREADS_PER_BLOCK];

    int tid = threadIdx.x;
    int batch_idx = blockIdx.x;

    if (batch_idx >= batch_size) return;

    const float* pred_ptr = predictions + batch_idx * feature_size;
    const float* target_ptr = targets + batch_idx * feature_size;

    // Initialize accumulators
    float dot_product = 0.0f;
    float norm_pred = 0.0f;
    float norm_target = 0.0f;

    // Vectorized processing for better memory bandwidth utilization
    // Calculate total iterations needed to cover all elements
    int total_iterations = (feature_size + THREADS_PER_BLOCK * ELEMENTS_PER_THREAD - 1) / (THREADS_PER_BLOCK * ELEMENTS_PER_THREAD);

    for (int iter = 0; iter < total_iterations; iter++) {
        int base = iter * THREADS_PER_BLOCK * ELEMENTS_PER_THREAD;
        int idx = base + tid * ELEMENTS_PER_THREAD;

        #pragma unroll
        for (int i = 0; i < ELEMENTS_PER_THREAD; i++) {
            int element_idx = idx + i;
            if (element_idx < feature_size) {
                float pred_val = pred_ptr[element_idx];
                float target_val = target_ptr[element_idx];
                dot_product += pred_val * target_val;
                norm_pred += pred_val * pred_val;
                norm_target += target_val * target_val;
            }
        }
    }

    // Store thread results in shared memory
    shared_dot[tid] = dot_product;
    shared_pred_norm[tid] = norm_pred;
    shared_target_norm[tid] = norm_target;
    __syncthreads();

    // Parallel reduction using warp shuffles for better efficiency
    // This reduction works correctly only for power-of-two thread counts
    for (int stride = THREADS_PER_BLOCK / 2; stride >= 32; stride >>= 1) {
        if (tid < stride) {
            shared_dot[tid] += shared_dot[tid + stride];
            shared_pred_norm[tid] += shared_pred_norm[tid + stride];
            shared_target_norm[tid] += shared_target_norm[tid + stride];
        }
        __syncthreads();
    }

    // Warp-level reduction (works for the first 32 threads)
    if (tid < 32) {
        // Ensure all 32 lanes are active for warp shuffle
        unsigned active_mask = __activemask();

        // Use proper warp reduction with correct mask
        shared_dot[tid] += __shfl_down_sync(active_mask, shared_dot[tid], 16);
        shared_pred_norm[tid] += __shfl_down_sync(active_mask, shared_pred_norm[tid], 16);
        shared_target_norm[tid] += __shfl_down_sync(active_mask, shared_target_norm[tid], 16);

        shared_dot[tid] += __shfl_down_sync(active_mask, shared_dot[tid], 8);
        shared_pred_norm[tid] += __shfl_down_sync(active_mask, shared_pred_norm[tid], 8);
        shared_target_norm[tid] += __shfl_down_sync(active_mask, shared_target_norm[tid], 8);

        shared_dot[tid] += __shfl_down_sync(active_mask, shared_dot[tid], 4);
        shared_pred_norm[tid] += __shfl_down_sync(active_mask, shared_pred_norm[tid], 4);
        shared_target_norm[tid] += __shfl_down_sync(active_mask, shared_target_norm[tid], 4);

        shared_dot[tid] += __shfl_down_sync(active_mask, shared_dot[tid], 2);
        shared_pred_norm[tid] += __shfl_down_sync(active_mask, shared_pred_norm[tid], 2);
        shared_target_norm[tid] += __shfl_down_sync(active_mask, shared_target_norm[tid], 2);

        shared_dot[tid] += __shfl_down_sync(active_mask, shared_dot[tid], 1);
        shared_pred_norm[tid] += __shfl_down_sync(active_mask, shared_pred_norm[tid], 1);
        shared_target_norm[tid] += __shfl_down_sync(active_mask, shared_target_norm[tid], 1);
    }
    __syncthreads();

    // First thread computes final loss for this batch
    if (tid == 0) {
        const float epsilon = 1e-8f;
        float norm_pred_sqrt = sqrtf(shared_pred_norm[0] + epsilon);
        float norm_target_sqrt = sqrtf(shared_target_norm[0] + epsilon);
        float norm_product = norm_pred_sqrt * norm_target_sqrt;
        float cosine_sim = shared_dot[0] / (norm_product + epsilon);
        float loss = 1.0f - cosine_sim;

        // Atomic add to accumulate mean
        atomicAdd(output, loss / batch_size);
    }
}

torch::Tensor cosine_loss_cuda(torch::Tensor predictions, torch::Tensor targets) {
    auto batch_size = predictions.size(0);
    auto feature_size = predictions.size(1);

    // Runtime validation
    if (batch_size <= 0 || feature_size <= 0) {
        throw std::runtime_error("Invalid tensor dimensions");
    }

    // Allocate output tensor (single value)
    auto options = torch::TensorOptions()
        .dtype(predictions.dtype())
        .device(predictions.device());
    auto output = torch::zeros({1}, options);

    // Choose optimal configuration based on feature size
    // Use compile-time constants with validation
    const int THREADS = 256;
    const int ELEMENTS_PER_THREAD = 4;

    // Compile-time assertions (will fail at compile time if constants are mutated incorrectly)
    // Note: These are implemented via template parameters in the kernel

    dim3 grid_size(batch_size, 1, 1);
    dim3 block_size(THREADS, 1, 1);

    // Launch fused kernel - one block per batch element
    cosine_loss_fused_kernel<THREADS, ELEMENTS_PER_THREAD><<<grid_size, block_size>>>(
        predictions.data_ptr<float>(),
        targets.data_ptr<float>(),
        output.data_ptr<float>(),
        batch_size,
        feature_size
    );

    // Check for CUDA errors
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        throw std::runtime_error(cudaGetErrorString(err));
    }

    return output.squeeze();
}
"""

cosine_loss_cpp_source = "torch::Tensor cosine_loss_cuda(torch::Tensor predictions, torch::Tensor targets);"

